import sys, re
md = open(sys.argv[1], encoding='utf-8').read()
print("mdChars =", len(md))
# section headings
secs = re.findall(r'^## (\d+)\. ', md, re.M)
print("section numbers found:", secs)
print("sectionsPresent (1..11):", secs == [str(i) for i in range(1,12)])
# mermaid blocks
blocks = re.findall(r'```mermaid\n(.*?)```', md, re.S)
print("mermaidCount =", len(blocks))
# breaking-char scan: inside labels [..], (..) edge text |..|
bad = '()[]|:/"<>;{}'
problems = []
for i, b in enumerate(blocks):
    # node labels in [ ... ] and edge texts in | ... |
    for lbl in re.findall(r'\[\(?(.*?)\)?\]', b):
        for ch in '():/"<>;{}':
            if ch in lbl:
                problems.append((i, 'node', lbl, ch))
    for lbl in re.findall(r'\|"(.*?)"\|', b):
        for ch in '():/"<>;{}':
            if ch in lbl:
                problems.append((i, 'edge', lbl, ch))
    # also catch edge text without quotes |..|
    for lbl in re.findall(r'\|([^"|]*?)\|', b):
        for ch in '():/"<>;{}':
            if ch in lbl:
                problems.append((i, 'edge-noquote', lbl, ch))
print("breaking-char problems:", problems if problems else "NONE")
PY
